(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[3739],{3731:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-4d05fe9b",path:"/pages/typescript/usefulTips/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"复制类型和值",slug:"复制类型和值",children:[]},{level:3,title:"多重继承",slug:"多重继承",children:[]},{level:3,title:"添加废弃注解",slug:"添加废弃注解",children:[]},{level:3,title:"ITypeA 类型的tag可以直接点击到ITag类型",slug:"itypea-类型的tag可以直接点击到itag类型",children:[]},{level:3,title:"tsconfig.json大括号报错",slug:"tsconfig-json大括号报错",children:[]},{level:3,title:"tsconfig.json references",slug:"tsconfig-json-references",children:[]},{level:3,title:"satisfies",slug:"satisfies",children:[]},{level:3,title:"枚举值 value 为string 类型时不会反映射",slug:"枚举值-value-为string-类型时不会反映射",children:[]},{level:3,title:"import 标红报错找不到tsconfig.json配置文件",slug:"import-标红报错找不到tsconfig-json配置文件",children:[]},{level:3,title:'模块“"fs"”没有默认导出',slug:"模块-fs-没有默认导出",children:[]},{level:3,title:"Cannot find module '*'. Did you mean to set the 'moduleResolution' option to 'node'",slug:"cannot-find-module-did-you-mean-to-set-the-moduleresolution-option-to-node",children:[]},{level:3,title:"模块化js如何规避循环引用",slug:"模块化js如何规避循环引用",children:[]},{level:3,title:"普通枚举与常量枚举",slug:"普通枚举与常量枚举",children:[]}],filePathRelative:"pages/typescript/usefulTips/README.md",git:{updatedTime:1709730609e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:8},{name:"guilin.li",email:"1344714332@qq.com",commits:2}]}}},5674:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>f});var e=a(6252);const p=(0,e.uE)('<h3 id="复制类型和值"><a class="header-anchor" href="#复制类型和值">#</a> 复制类型和值</h3><p>如果你想移动一个类，你可能会想要做以下事情：</p><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token keyword">class</span> <span class="token class-name">Foo</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n<span class="token keyword">const</span> Bar <span class="token operator">=</span> Foo<span class="token punctuation">;</span>\n<span class="token keyword">let</span> bar<span class="token operator">:</span> Bar<span class="token punctuation">;</span> <span class="token comment">// Error: 不能找到名称 &#39;Bar&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这会得到一个错误，因为 const 仅仅是复制了 Foo 到一个变量声明空间，因此你无法把 Bar 当作一个类型声明使用。正确的方式是使用 import 关键字，请注意，如果你在使用 namespace 或者 modules，使用 import 是你唯一能用的方式：</p><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token keyword">namespace</span> importing <span class="token punctuation">{</span>\n  <span class="token keyword">export</span> <span class="token keyword">class</span> <span class="token class-name">Foo</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">import</span> Bar <span class="token operator">=</span> importing<span class="token punctuation">.</span>Foo<span class="token punctuation">;</span>\n<span class="token keyword">let</span> bar<span class="token operator">:</span> Bar<span class="token punctuation">;</span> <span class="token comment">// ok</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个 import 技巧，仅适合于类型和变量。</p><h3 id="多重继承"><a class="header-anchor" href="#多重继承">#</a> 多重继承</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>「混合」是一个函数： 传入一个构造函数； 创建一个带有新功能，并且扩展构造函数的新类； 返回这个新类。</p></div><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token comment">// 所有 mixins 都需要</span>\n<span class="token keyword">type</span> <span class="token class-name">Constructor<span class="token operator">&lt;</span><span class="token constant">T</span> <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token operator">&gt;</span></span> <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token punctuation">(</span><span class="token operator">...</span>args<span class="token operator">:</span> <span class="token builtin">any</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token constant">T</span><span class="token punctuation">;</span>\n\n<span class="token comment">/////////////</span>\n<span class="token comment">// mixins 例子</span>\n<span class="token comment">////////////</span>\n\n<span class="token comment">// 添加属性的混合例子</span>\n<span class="token keyword">function</span> <span class="token generic-function"><span class="token function">TimesTamped</span><span class="token generic class-name"><span class="token operator">&lt;</span>TBase <span class="token keyword">extends</span> Constructor<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>Base<span class="token operator">:</span> TBase<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token keyword">class</span> <span class="token class-name"><span class="token keyword">extends</span></span> Base <span class="token punctuation">{</span>\n    timestamp <span class="token operator">=</span> Date<span class="token punctuation">.</span><span class="token function">now</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token comment">// 添加属性和方法的混合例子</span>\n<span class="token keyword">function</span> <span class="token generic-function"><span class="token function">Activatable</span><span class="token generic class-name"><span class="token operator">&lt;</span>TBase <span class="token keyword">extends</span> Constructor<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>Base<span class="token operator">:</span> TBase<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token keyword">return</span> <span class="token keyword">class</span> <span class="token class-name"><span class="token keyword">extends</span></span> Base <span class="token punctuation">{</span>\n    isActivated <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">;</span>\n\n    <span class="token function">activate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token keyword">this</span><span class="token punctuation">.</span>isActivated <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n\n    <span class="token function">deactivate</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n      <span class="token keyword">this</span><span class="token punctuation">.</span>isActivated <span class="token operator">=</span> <span class="token boolean">false</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token comment">///////////</span>\n<span class="token comment">// 组合类</span>\n<span class="token comment">///////////</span>\n\n<span class="token comment">// 简单的类</span>\n<span class="token keyword">class</span> <span class="token class-name">User</span> <span class="token punctuation">{</span>\n  name <span class="token operator">=</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token comment">// 添加 TimesTamped 的 User</span>\n<span class="token keyword">const</span> TimestampedUser <span class="token operator">=</span> <span class="token function">TimesTamped</span><span class="token punctuation">(</span>User<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n<span class="token comment">// Tina TimesTamped 和 Activatable 的类</span>\n<span class="token keyword">const</span> TimestampedActivatableUser <span class="token operator">=</span> <span class="token function">TimesTamped</span><span class="token punctuation">(</span><span class="token function">Activatable</span><span class="token punctuation">(</span>User<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n<span class="token comment">//////////</span>\n<span class="token comment">// 使用组合类</span>\n<span class="token comment">//////////</span>\n\n<span class="token keyword">const</span> timestampedUserExample <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TimestampedUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>timestampedUserExample<span class="token punctuation">.</span>timestamp<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n<span class="token keyword">const</span> timestampedActivatableUserExample <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">TimestampedActivatableUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>timestampedActivatableUserExample<span class="token punctuation">.</span>timestamp<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>timestampedActivatableUserExample<span class="token punctuation">.</span>isActivated<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br></div></div><h3 id="添加废弃注解"><a class="header-anchor" href="#添加废弃注解">#</a> 添加废弃注解</h3><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token punctuation">{</span>\n    <span class="token doc-comment comment">/**\n     * <span class="token keyword">@deprecated</span> 该属性即将禁用，请使用 style属性\n     */</span>\n    className<span class="token operator">?</span><span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>\n    <span class="token function-variable function">onClick</span><span class="token operator">:</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token keyword">void</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="itypea-类型的tag可以直接点击到itag类型"><a class="header-anchor" href="#itypea-类型的tag可以直接点击到itag类型">#</a> ITypeA 类型的tag可以直接点击到ITag类型</h3><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token comment">// types.ts</span>\n<span class="token keyword">export</span> <span class="token keyword">interface</span> <span class="token class-name">ITypeA</span> <span class="token punctuation">{</span>\n  <span class="token doc-comment comment">/**\n   * tag 标签 <span class="token punctuation">{</span><span class="token keyword">@link</span> ITag<span class="token punctuation">}</span>.\n   */</span>\n  tag<span class="token operator">:</span> ITag<span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n\n<span class="token keyword">export</span> <span class="token keyword">interface</span> <span class="token class-name">ITag</span> <span class="token punctuation">{</span>\n  <span class="token doc-comment comment">/** tag id */</span>\n  id<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>\n  <span class="token doc-comment comment">/** tag name */</span>\n  name<span class="token operator">:</span> <span class="token builtin">string</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n<span class="token comment">// 参考链接 https://juejin.cn/post/7140337202097029133</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>当我们在使用字面量创建了一个正则表达式的时候，相当于初始化了一个对象，这个对象上有一个叫做lastIndex的属性</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> reg <span class="token operator">=</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">[^0-9]</span><span class="token regex-delimiter">/</span><span class="token regex-flags">g</span></span><span class="token punctuation">;</span>\n\nreg<span class="token punctuation">.</span><span class="token function">test</span><span class="token punctuation">(</span><span class="token string">&#39;a&#39;</span><span class="token punctuation">)</span>  <span class="token comment">// true</span>\n\nreg<span class="token punctuation">.</span>lastIndex <span class="token comment">// 1</span>\n\nreg<span class="token punctuation">.</span><span class="token function">test</span><span class="token punctuation">(</span><span class="token string">&#39;a&#39;</span><span class="token punctuation">)</span> <span class="token comment">// false</span>\n\nreg<span class="token punctuation">.</span>lastIndex <span class="token comment">// 0</span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="tsconfig-json大括号报错"><a class="header-anchor" href="#tsconfig-json大括号报错">#</a> tsconfig.json大括号报错</h3><p>使用 消除这个报错</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  compilerOption<span class="token operator">:</span> <span class="token punctuation">{</span>\n    ignoreDeprecations：<span class="token string">&quot;5.0&quot;</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="tsconfig-json-references"><a class="header-anchor" href="#tsconfig-json-references">#</a> tsconfig.json references</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>references指定工程引用依赖。在多子项目中共享配置文件</p></div><h3 id="satisfies"><a class="header-anchor" href="#satisfies">#</a> satisfies</h3><p>satisfies 这个语法。它的作用就是让你用自动推导出的类型，而不是声明的类型，增加灵活性，同时还可以对这个推导出的类型做类型检查，保证安全。</p><h3 id="枚举值-value-为string-类型时不会反映射"><a class="header-anchor" href="#枚举值-value-为string-类型时不会反映射">#</a> 枚举值 value 为string 类型时不会反映射</h3><div class="language-typescript ext-ts line-numbers-mode"><pre class="language-typescript"><code><span class="token keyword">enum</span> <span class="token constant">NUM</span> <span class="token punctuation">{</span>\n  <span class="token constant">A</span> <span class="token operator">=</span> <span class="token number">1</span><span class="token punctuation">,</span>\n  <span class="token constant">B</span> <span class="token operator">=</span> <span class="token number">2</span><span class="token punctuation">,</span>\n  <span class="token constant">C</span> <span class="token operator">=</span> <span class="token string">&#39;3&#39;</span><span class="token punctuation">,</span>\n  <span class="token constant">D</span> <span class="token operator">=</span> <span class="token string">&#39;demo&#39;</span>\n<span class="token punctuation">}</span>\n<span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>Object<span class="token punctuation">.</span><span class="token function">entires</span><span class="token punctuation">(</span><span class="token constant">NUM</span><span class="token punctuation">)</span><span class="token punctuation">)</span> \n<span class="token constant">NUM</span><span class="token punctuation">[</span><span class="token number">1</span><span class="token punctuation">]</span> <span class="token operator">===</span> <span class="token string">&#39;A&#39;</span>\n<span class="token constant">NUM</span><span class="token punctuation">[</span><span class="token number">2</span><span class="token punctuation">]</span> <span class="token operator">===</span> <span class="token string">&#39;B&#39;</span>\n<span class="token constant">NUM</span><span class="token punctuation">[</span><span class="token string">&#39;demo&#39;</span><span class="token punctuation">]</span> <span class="token operator">!==</span> <span class="token string">&#39;D&#39;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h3 id="import-标红报错找不到tsconfig-json配置文件"><a class="header-anchor" href="#import-标红报错找不到tsconfig-json配置文件">#</a> import 标红报错找不到tsconfig.json配置文件</h3><p>原因: .eslintrc 配置的 tsconfig.json的路径不对</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>\n  parserOptions<span class="token operator">:</span> <span class="token punctuation">{</span> project<span class="token operator">:</span> <span class="token punctuation">[</span>&#39;/tsconfig.json&#39;<span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> \n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这个时候一般我们的项目处于子目录中，可以使用相对路径指定tsconfig.json的路径 需要将.eslintrc 文件改成 .eslintrc.js 然后使用__dirname获取相对路径</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  parser<span class="token operator">:</span> <span class="token string">&#39;@typescript-eslint/parser&#39;</span><span class="token punctuation">,</span>\n  parserOptions<span class="token operator">:</span> <span class="token punctuation">{</span> project<span class="token operator">:</span> <span class="token punctuation">[</span>__dirname <span class="token operator">+</span> <span class="token string">&#39;/tsconfig.json&#39;</span><span class="token punctuation">]</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="模块-fs-没有默认导出"><a class="header-anchor" href="#模块-fs-没有默认导出">#</a> 模块“&quot;fs&quot;”没有默认导出</h3><ul><li>1 可以使用 import * as fs from &#39;fs&#39;</li><li>2 或者在tsconfig.json的compilation填加属性&quot;esModuleInterop&quot;: true</li></ul><h3 id="cannot-find-module-did-you-mean-to-set-the-moduleresolution-option-to-node"><a class="header-anchor" href="#cannot-find-module-did-you-mean-to-set-the-moduleresolution-option-to-node">#</a> Cannot find module &#39;*&#39;. Did you mean to set the &#39;moduleResolution&#39; option to &#39;node&#39;</h3><p>-1 在tsconfig.json的compilation填加属性&quot;moduleResolution&quot;: &quot;node&quot;</p>',33),t={class:"custom-container tip"},o=(0,e.Wm)("p",{class:"custom-container-title"},"TIP",-1),c=(0,e.Wm)("p",null,"模块解析策略（ moduleResolution）更多描述的是一个模块包括相对路径以及非相对路径（也就是第三方库，亦或者说 npm 包）是按照怎样的规则去查找的 现在支持的值有三个classic、node",-1),l=(0,e.Wm)("li",null,"classic 简单来说这种模块解析策略就是一直递归往上找同名文件，当前目录找不到同名文件就往父级目录找。不过这种策略目前前端界用得不多",-1),r=(0,e.Uk)("相比于 classic 策略的区别在于： "),i=(0,e.Wm)("li",null,"递归查找的目录是 node_modules，不是父级文件夹",-1),u=(0,e.Wm)("li",null,"引入了 package.json，各种配置项尤其是后面会展开说的 exports 字段使得 node 模块解析策略的变得非常复杂",-1),k=(0,e.Uk)("支持文件夹模块，也就是 pkg/index.js，文件夹中包含 index.js，这个文件夹就是一个模块 "),m={href:"https://zhuanlan.zhihu.com/p/621795173",target:"_blank",rel:"noopener noreferrer"},b=(0,e.Uk)("参考资料"),d={href:"https://arethetypeswrong.github.io/",target:"_blank",rel:"noopener noreferrer"},g=(0,e.Uk)("用来检测npm的moduleResolution是否合理"),h=(0,e.uE)('<h3 id="模块化js如何规避循环引用"><a class="header-anchor" href="#模块化js如何规避循环引用">#</a> 模块化js如何规避循环引用</h3><p>CommonJS和ES Module都对循环引入做了处理，不会进入死循环，但方式不同：</p><ul><li>CommonJS借助模块缓存，遇到require函数会先检查是否有缓存，已经有的则不会进入执行，在模块缓存中还记录着导出的变量的拷贝值；</li><li>ES Module借助模块地图，已经进入过的模块标注为获取中，遇到import语句会去检查这个地图，已经标注为获取中的则不会进入，地图中的每一个节点是一个模块记录，上面有导出变量的内存地址，导入时会做一个连接——即指向同一块内存。</li><li>有时会项目编译报错因为循环引用使得变量未定义就使用了。</li></ul><h3 id="普通枚举与常量枚举"><a class="header-anchor" href="#普通枚举与常量枚举">#</a> 普通枚举与常量枚举</h3><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>普通枚举 enum A {...} 和常量枚举 const enum A {...} 之间的区别主要在于 TS 的编译结果上有所差别 普通枚举 enum A {...}, 会将其编译为一个 JS 对象, 对象内就是枚举成员和值的一个相互映射 常量枚举 const enum A {...}, 编译后不会生成任何代码, 会删除 TS 部分内容, 对于使用到的成员只会进行值的替换 常量枚举 会有更好的性能, 避免额外的性能开销</p></div>',5),f={render:function(n,s){const a=(0,e.up)("OutboundLink");return(0,e.wg)(),(0,e.j4)(e.HY,null,[p,(0,e.Wm)("div",t,[o,c,(0,e.Wm)("ul",null,[l,(0,e.Wm)("li",null,[r,(0,e.Wm)("ul",null,[i,u,(0,e.Wm)("li",null,[k,(0,e.Wm)("a",m,[b,(0,e.Wm)(a)]),(0,e.Wm)("a",d,[g,(0,e.Wm)(a)])])])])])]),h],64)}}}}]);